const crypto = require('crypto');

const input = $input.first()?.json ?? {};
const state = $getWorkflowStaticData('global');
const monitoredUrl = $env.MONITOR_URL || 'https://eigensol.com';

const statusCode = typeof input.statusCode === 'number' ? input.statusCode : null;
const responseBody = typeof input.body === 'string'
  ? input.body
  : typeof input.data === 'string'
    ? input.data
    : '';
const errorText = [
  input.error?.message,
  input.message,
  input.reason,
  input.description,
].filter(Boolean).join(' ');

const normalizedContent = responseBody.replace(/\s+/g, ' ').trim();
const newHash = crypto.createHash('md5').update(normalizedContent).digest('hex');
const newLength = normalizedContent.length;
const oldHash = typeof state.hash === 'string' ? state.hash : '';
const oldLength = typeof state.length === 'number' ? state.length : 0;
const currentDay = new Date().toISOString().slice(0, 10);

const looksDown = Boolean(errorText)
  || (statusCode !== null && statusCode >= 500)
  || newLength < 500
  || /\b(error|502|503|504|cloudflare|temporarily unavailable)\b/i.test(normalizedContent);

let status = 'unchanged';
let notificationReason = '';
let shouldNotify = false;
let summaryPrompt = '';

if (!oldHash) {
  status = 'first_run';
} else if (looksDown) {
  status = 'site_down';
} else if (newHash === oldHash) {
  status = 'unchanged';
} else if (newLength > oldLength) {
  status = 'increased';
} else {
  status = 'decreased';
}

if (status === 'first_run') {
  shouldNotify = true;
  notificationReason = 'startup';
  summaryPrompt = `Website ${monitoredUrl} was checked after monitoring started, and nothing updated. Write exactly 2 short sentences that say monitoring is running and nothing changed yet.`;
  state.lastDailyNotificationDate = currentDay;
} else if (status === 'unchanged') {
  if (state.lastDailyNotificationDate !== currentDay) {
    shouldNotify = true;
    notificationReason = 'daily_heartbeat';
    summaryPrompt = `Website ${monitoredUrl} was checked and nothing updated since the previous checks. Write exactly 2 short sentences that clearly say nothing updated today.`;
    state.lastDailyNotificationDate = currentDay;
  }
} else {
  shouldNotify = true;
  notificationReason = 'change';
  summaryPrompt = `Website ${monitoredUrl} status changed. Status: ${status}. Old size: ${oldLength} chars. New size: ${newLength} chars. Write exactly 2 short sentences summarizing what happened. Be direct.`;
}

state.hash = newHash;
state.length = newLength;
state.lastStatusCode = statusCode;
state.lastCheckedAt = new Date().toISOString();

if (!shouldNotify) {
  return [];
}

return [{
  json: {
    monitoredUrl,
    status,
    statusCode,
    newHash,
    oldHash,
    newLength,
    oldLength,
    preview: normalizedContent.slice(0, 300),
    errorText,
    notificationReason,
    summaryPrompt,
  },
}];

const fs = require('fs');

const groqResponse = $input.first()?.json ?? {};
const change = $('Classify Change').first().json;

const rawMessage = groqResponse.choices?.[0]?.message?.content
  ?? groqResponse.message
  ?? groqResponse.error?.message
  ?? 'Groq summary unavailable.';
const message = String(rawMessage).replace(/\s+/g, ' ').trim();
const timestamp = new Date().toISOString();
const logLine = `[${timestamp}] STATUS: ${change.status} | ${message}\n`;

fs.mkdirSync('/files', { recursive: true });
fs.appendFileSync('/files/automation.log', logLine, 'utf8');

return [{
  json: {
    status: change.status,
    logLine: logLine.trimEnd(),
    message,
  },
}];
